def gen(rng, size):
    n = max(1, min(200, size))
    m = [[0] * n for _ in range(n)]
    for i in range(n):
        m[i][i] = 1
    for i in range(n):
        for j in range(i + 1, n):
            if rng.random() < 0.05:
                m[i][j] = 1
                m[j][i] = 1
    return [m]

