class Solution:
    def findCircleNum(self, isConnected):
        n = len(isConnected)
        parent = list(range(n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        for i in range(n):
            for j in range(n):
                if isConnected[i][j] == 1:
                    parent[find(i)] = find(j)
        return len({find(i) for i in range(n)})

