class Solution:
    def findCircleNum(self, isConnected):
        n = len(isConnected)
        seen = [False] * n
        count = 0
        for start in range(n):
            if seen[start]:
                continue
            count += 1
            stack = [start]
            seen[start] = True
            while stack:
                c = stack.pop()
                for nb in range(n):
                    if isConnected[c][nb] == 1 and not seen[nb]:
                        seen[nb] = True
                        stack.append(nb)
        return count

