var findCircleNum = function(isConnected) {
    const n = isConnected.length;
    const seen = new Array(n).fill(false);
    let count = 0;
    for (let start = 0; start < n; start++) {
        if (seen[start]) continue;
        count++;
        const stack = [start];
        seen[start] = true;
        while (stack.length) {
            const c = stack.pop();
            for (let nb = 0; nb < n; nb++) {
                if (isConnected[c][nb] === 1 && !seen[nb]) {
                    seen[nb] = true;
                    stack.push(nb);
                }
            }
        }
    }
    return count;
};
